   &return.type.true.84;


    8.3.0

     Вызов метода Phar::setStub с ресурсом (resource) в первом аргументе,
     для которого передавали аргумент length, — устарел,
     и теперь заменяется вызовом: $phar->setStub(stream_get_contents($resource));.

  &reftitle.examples;



    Пример установки начальной загрузочной заглушки методом Phar::setStub





<?php

try {
    $p = new Phar(dirname(__FILE__) . '/brandnewphar.phar', 0, 'brandnewphar.phar');

    $p['a.php'] = '<?php var_dump("Привет,");';
    $p->setStub('<?php var_dump("Первый загрузчик"); Phar::mapPhar("brandnewphar.phar"); __HALT_COMPILER(); ?>');
    include 'phar://brandnewphar.phar/a.php';
    var_dump($p->getStub());

    $p['b.php'] = '<?php var_dump(" мир!");';
    $p->setStub('<?php var_dump("Второй загрузчик"); Phar::mapPhar("brandnewphar.phar"); __HALT_COMPILER(); ?>');
    include 'phar://brandnewphar.phar/b.php';
    var_dump($p->getStub());
} catch (Exception $e) {
    echo 'При записи операций в архив brandnewphar.phar возникла ошибка: ', $e;
}


    &example.outputs;


string(13) "Привет,"
